import asyncio
import click
import sys
from pathlib import Path
import os

# If running in a versioned environment, force the version's site-packages to the front.
opencode_version = os.environ.get('OPENCODE_VERSION')
if opencode_version:
    try:
        # Assumes this file is at /versions/vX.Y/site-packages/opencode/cli.py
        version_dir = Path(__file__).parent.parent.parent
        version_site_packages = version_dir / 'site-packages'
        if version_site_packages.exists() and str(version_site_packages) not in sys.path:
            sys.path.insert(0, str(version_site_packages))
            print(f"--- [CLI RUNNER] Patched sys.path to prioritize version: {opencode_version} ---")
    except Exception as e:
        print(f"--- [CLI RUNNER] WARNING: Failed to patch sys.path: {e} ---")

from rich.console import Console
from rich.markdown import Markdown
from rich.syntax import Syntax
from rich.panel import Panel

from .config import Config
from .ollama_client import OllamaClient
from .interactive import InteractiveMode
from .tools import ToolManager

console = Console()

@click.command()
@click.option('--model', '-m', help='Ollama model to use')
@click.option('--file', '-f', help='File to analyze or modify')
@click.option('--config', '-c', help='Path to config file')
@click.option('--interactive', '-i', is_flag=True, help='Start in interactive mode')
@click.option('--verbose', '-v', is_flag=True, help='Verbose output')
@click.argument('prompt', required=False)
def main(model, file, config, interactive, verbose, prompt):
    """OpenCode - AI-powered code assistant using Ollama"""
    asyncio.run(async_main(model, file, config, interactive, verbose, prompt))

import logging

logger = logging.getLogger(__name__)

async def async_main(model, file, config, interactive, verbose, prompt):
    """Async main function"""
    
    # Initialize logging; prefer project-local logs directory to avoid permission issues
    try:
        logs_dir = Path(__file__).parent.parent / "logs"
        logs_dir.mkdir(parents=True, exist_ok=True)
        log_file = logs_dir / "opencode_debug.log"
        logging.basicConfig(level=logging.INFO, filename=str(log_file), filemode='w',
                            format='%(asctime)s - %(levelname)s - %(message)s')
    except Exception:
        # Fallback to stdout logging if file not writable
        logging.basicConfig(level=logging.INFO,
                            format='%(asctime)s - %(levelname)s - %(message)s')
    logger.debug("Starting async_main")

    # Load configuration
    config_path = config or "config.yaml"
    try:
        cfg = Config.load(config_path)
    except FileNotFoundError:
        # Try to find config in package directory
        package_config = Path(__file__).parent / "config.yaml"
        if package_config.exists():
            cfg = Config.load(str(package_config))
        else:
            console.print(f"[red]Config file not found: {config_path}[/red]")
            console.print("[yellow]Using default configuration[/yellow]")
            cfg = Config()
    
    # Override model if specified
    if model:
        cfg.model.name = model

    async with OllamaClient(cfg.model) as ollama_client:
        tool_manager = ToolManager(cfg.tools)

        # Check if Ollama is available / model present
        # In interactive mode, warn but do not hard-exit to avoid closing the UI immediately.
        ollama_ok = await ollama_client.is_available()
        model_ok = False
        if ollama_ok:
            model_ok = await ollama_client.is_model_available()

        if not ollama_ok:
            console.print("[yellow]Warning: Ollama is not available. Some features will be disabled.[/yellow]")
            console.print("[dim]Tip: Start it with 'ollama serve' in another terminal.[/dim]")
        elif not model_ok:
            console.print(f"[yellow]Warning: Model '{cfg.model.name}' is not available.[/yellow]")
            console.print(f"[dim]Tip: Run 'ollama pull {cfg.model.name}' to install it.[/dim]")

        if interactive or not prompt:
            # Start interactive mode
            interactive_mode = InteractiveMode(ollama_client, tool_manager, cfg)
            await interactive_mode.run()
        else:
            # Direct command mode: require service/model availability
            if not ollama_ok:
                console.print("[red]Error: Ollama is not available. Aborting direct command.[/red]")
                sys.exit(1)
            if not model_ok:
                console.print(f"[red]Error: Model '{cfg.model.name}' is not available. Aborting direct command.[/red]")
                sys.exit(1)
            await handle_direct_command(ollama_client, tool_manager, cfg, prompt, file, verbose)

async def handle_direct_command(ollama_client, tool_manager, cfg, prompt, file, verbose):
    """Handle direct command execution"""
    
    # Add file context if specified
    context = ""
    if file:
        # Use the secure file read tool
        file_result = await tool_manager.execute_tool('file_read', file_path=file)
        if file_result.success:
            context = f"File: {file}\n\n{file_result.output}\n\n"
        else:
            console.print(f"[red]Error reading file: {file_result.error}[/red]")
            return
    
    full_prompt = context + prompt
    
    if verbose:
        console.print(f"[dim]Using model: {cfg.model.name}[/dim]")
        if file:
            console.print(f"[dim]Analyzing file: {file}[/dim]")
        console.print(f"[dim]Prompt: {prompt}[/dim]")
        console.print("[dim]" + "="*50 + "[/dim]")
    
    try:
        # Generate response
        response = await ollama_client.generate(full_prompt, cfg.system_prompt)
        
        # Display response
        if response.strip().startswith('```'):
            # Code response
            console.print(Syntax(response, "markdown", theme="monokai"))
        else:
            # Regular response
            console.print(Markdown(response))
            
    except Exception as e:
        console.print(f"[red]Error: {e}[/red]")
        sys.exit(1)

if __name__ == "__main__":
    asyncio.run(main())
